        //|000|da427fb5401748e69cb067d5ae65e4b7|0e5ec6854b2948f799ef2e2da4a951a7|Successful vote validation|#encryptedOptions=";" #ccx_id="ccn_c1" #voteSignature="" #request_id="WAD2KEU3UVTPP6QX" #hash_Vote="apiIs8P9wfoDwugx06DwAe8+VBd10hDww0zS5A/uo4Y=" #encryptedWriteIns="null" #schnorrProof="{"zkProof":{"q":"","hash":"Gu9qcCjTjZmCZyRgMQlx+MJOgblryKi3y1zFteY//XQ=","values":[""]}}" #correctnessIds="[["c7ccd420c40e441db02b524f33bc6ea8"],["3e089b1d641e4157b4cf4adedd7cc405"],["3e089b1d641e4157b4cf4adedd7cc405"],["3e089b1d641e4157b4cf4adedd7cc405"],["3e089b1d641e4157b4cf4adedd7cc405"],["3e089b1d641e4157b4cf4adedd7cc405"],["3e089b1d641e4157b4cf4adedd7cc405"],["3e089b1d641e4157b4cf4adedd7cc405"]]" #auhTokenSignature="" #verCardPKSignature="
